    const trimmed = p.trim();
    if (trimmed.includes('{')) {
      const inner = (trimmed.startsWith('{') && trimmed.endsWith('}'))
        ? trimmed.slice(1, -1)
        : trimmed.replace(/[{}]/g, '');
      const parts = inner.split('|');
      return doReplacements(parts[0] ?? '');
    }
